const raw = $('Get_info_mail1').first().json.text || '';
// Strip citations Gmail                                                                                                                    
const clean = raw.split(/\r?\n\s*Le .+(?:a écrit|a .crit)\s*:/)[0].trim();
// Strip signature
const final = clean.split(/\r?\n--\s*\r?\n/)[0].trim();
return [{ json: { cleaned_message: final } }];

